<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';use App\Repositories\ControlEscaneres\Pdo\{PdoScannerRepository,PdoScannerMovementRepository,PdoScannerInspectionRepository,PdoScannerIncidentRepository,PdoEvidenceRepository,PdoAuditRepository};use App\Repositories\ControlEscaneres\TransactionManager;use App\DTO\ControlEscaneres\{ScannerCreateData,ScannerUpdateData,ScannerFilterData,AuthenticatedActorData,ScannerMovementCreateData,ScannerInspectionCreateData,ScannerInspectionDetailData,ScannerIncidentCreateData,ScannerEvidenceMetadata,AuditEventData};use App\Domain\ControlEscaneres\{ScannerCode,ScannerStatus,ScannerFolio,InspectionType,IncidentSeverity};
$pdo=new PDO('sqlite::memory:');$pdo->exec(file_get_contents(__DIR__.'/fixtures/sqlite-schema.sql'));$actor=new AuthenticatedActorData(7,'test');$sc=new PdoScannerRepository($pdo);$created=$sc->create(new ScannerCreateData(new ScannerCode('SC-0001'),'QR1','Zebra','TC22',new ScannerStatus('disponible')),7);
test('crear y buscar',fn()=>same('SC-0001',(string)$sc->findById($created->id)->code));test('buscar código',fn()=>ok($sc->findByCode(new ScannerCode('SC-0001'))!==null));test('duplicado',fn()=>throws(fn()=>$sc->create(new ScannerCreateData(new ScannerCode('SC-0001'),'QR2','Z','M',new ScannerStatus('disponible')),7)));$sc->update($created->id,new ScannerUpdateData('QR1','Honeywell','EDA'),7);$sc->changeStatus($created->id,new ScannerStatus('entregado'),7);test('cambio estado',fn()=>same('entregado',(string)$sc->findById($created->id)->status));test('lista paginada',fn()=>same(1,count($sc->list(new ScannerFilterData()))));$mv=new PdoScannerMovementRepository($pdo);$m=$mv->create(new ScannerMovementCreateData($created->id,new ScannerFolio('MOV-20260718-ABC123'),'Persona','E1','A',new DateTimeImmutable(),$actor));test('movimiento abierto',fn()=>ok($mv->hasOpenMovement($created->id)));$mv->closeAsReturned($m->id,new DateTimeImmutable(),7,'Responsable');test('cierre',fn()=>same(0,$mv->countOpen()));$ins=new PdoScannerInspectionRepository($pdo);$ins->createInspection(new ScannerInspectionCreateData($m->id,$created->id,new InspectionType('entrega'),new DateTimeImmutable(),$actor,[new ScannerInspectionDetailData('pantalla','bueno')]));$ins->createInspection(new ScannerInspectionCreateData($m->id,$created->id,new InspectionType('recepcion'),new DateTimeImmutable(),$actor,[new ScannerInspectionDetailData('pantalla','malo')]));test('comparación empeoró',fn()=>same('empeoro',$ins->compareDeliveryAndReturn($m->id)[0]['resultado']));$ir=new PdoScannerIncidentRepository($pdo);$inc=$ir->create(new ScannerIncidentCreateData($created->id,'daño',new IncidentSeverity('alta'),'Pantalla',new DateTimeImmutable(),$actor));$ir->resolve($inc->id,'Cambio',7,new DateTimeImmutable());test('incidencia resuelta',fn()=>same(0,$ir->countOpenBySeverity(new IncidentSeverity('alta'))));$ev=new PdoEvidenceRepository($pdo);test('evidencia',fn()=>ok($ev->create(new ScannerEvidenceMetadata($created->id,'foto','x.jpg','image/jpeg',10,str_repeat('a',64),new DateTimeImmutable(),$actor))>0));$au=new PdoAuditRepository($pdo);$au->append(new AuditEventData($actor,'create','ce','scanner','exito',new DateTimeImmutable(),$created->id,['password'=>'x','safe'=>1]));test('auditoría sanitizada',function()use($pdo){$j=$pdo->query('SELECT valor_anterior_json FROM auditoria_eventos')->fetchColumn();ok(!str_contains($j,'password')&&str_contains($j,'safe'));});$tm=new TransactionManager($pdo);test('rollback',function()use($tm,$pdo){throws(fn()=>$tm->transactional(function()use($pdo){$pdo->exec("INSERT INTO scanners(codigo,codigo_qr,marca,modelo,estado)VALUES('SC-9999','Q','X','Y','disponible')");throw new RuntimeException();}));same(0,(int)$pdo->query("SELECT COUNT(*) FROM scanners WHERE codigo='SC-9999'")->fetchColumn());});$sc->deactivate($created->id,7);test('baja lógica',fn()=>same(0,count($sc->list(new ScannerFilterData()))));finish('Integration Control de Escáneres');
